using System.ComponentModel;
using System.Text.Json;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides web search capability for the research agent.
/// Replace the simulated implementation with a real search API (e.g., Bing Search) for production use.
/// </summary>
public sealed class WebSearchTool
{
    private readonly HttpClient _httpClient;
    private readonly ILogger<WebSearchTool> _logger;

    public WebSearchTool(HttpClient httpClient, ILogger<WebSearchTool> logger)
    {
        _httpClient = httpClient;
        _logger = logger;
    }

    [Description("Searches the web for information on a given query. Returns a list of relevant results with titles, snippets, and URLs.")]
    public async Task<string> SearchWebAsync(
        [Description("The search query to look up on the web")] string query,
        [Description("Maximum number of results to return (1-10)")] int maxResults = 5,
        CancellationToken cancellationToken = default)
    {
        _logger.LogInformation("Searching web for: {Query}", query);

        // In production, replace with a real search API call:
        // var response = await _httpClient.GetAsync($"https://api.bing.microsoft.com/v7.0/search?q={Uri.EscapeDataString(query)}&count={maxResults}", cancellationToken);
        var results = await SimulateSearchAsync(query, maxResults, cancellationToken);

        _logger.LogInformation("Found {Count} results for: {Query}", results.Count, query);
        return JsonSerializer.Serialize(results, new JsonSerializerOptions { WriteIndented = true });
    }

    private Task<List<SearchResult>> SimulateSearchAsync(string query, int maxResults, CancellationToken cancellationToken)
    {
        // Simulated search results for demonstration purposes.
        // Replace this with actual HTTP calls to a search API in production.
        var results = new List<SearchResult>
        {
            new($"Overview of {query}", $"https://example.com/{Uri.EscapeDataString(query)}/overview",
                $"A comprehensive overview covering the key aspects of {query}, including recent developments and expert analysis."),
            new($"Latest Research on {query}", $"https://research.example.com/{Uri.EscapeDataString(query)}",
                $"Recent peer-reviewed research findings related to {query}, published in leading journals."),
            new($"{query} - Expert Analysis", $"https://analysis.example.com/{Uri.EscapeDataString(query)}",
                $"In-depth expert analysis of {query} with data-driven insights and future predictions."),
            new($"Practical Guide to {query}", $"https://guides.example.com/{Uri.EscapeDataString(query)}",
                $"A hands-on guide explaining {query} with real-world examples and applications."),
            new($"{query}: History and Impact", $"https://history.example.com/{Uri.EscapeDataString(query)}",
                $"Exploring the historical context of {query} and its broader impact on society and technology."),
        };

        return Task.FromResult(results.Take(maxResults).ToList());
    }
}

public sealed record SearchResult(string Title, string Url, string Snippet);

using System.ComponentModel;
using System.Text;

namespace ResearchAgent.Tools;

/// <summary>
/// Provides note-taking capability for the research agent to organize findings.
/// </summary>
public sealed class NoteTakingTool
{
    private readonly List<ResearchNote> _notes = [];
    private readonly ILogger<NoteTakingTool> _logger;

    public NoteTakingTool(ILogger<NoteTakingTool> logger)
    {
        _logger = logger;
    }

    [Description("Saves a research note with a title and content. Use this to record key findings, facts, or insights discovered during research.")]
    public string SaveNote(
        [Description("A short descriptive title for the note")] string title,
        [Description("The content of the note with the research finding or insight")] string content,
        [Description("The source URL where this information was found, if applicable")] string? sourceUrl = null)
    {
        var note = new ResearchNote(title, content, sourceUrl, DateTime.UtcNow);
        _notes.Add(note);
        _logger.LogInformation("Saved note #{Number}: {Title}", _notes.Count, title);
        return $"Note saved successfully: \"{title}\" (Note #{_notes.Count})";
    }

    [Description("Retrieves all saved research notes collected so far.")]
    public string GetAllNotes()
    {
        if (_notes.Count == 0)
        {
            return "No notes have been saved yet.";
        }

        var sb = new StringBuilder();
        sb.AppendLine($"=== Research Notes ({_notes.Count} total) ===");
        sb.AppendLine();

        for (int i = 0; i < _notes.Count; i++)
        {
            var note = _notes[i];
            sb.AppendLine($"--- Note #{i + 1}: {note.Title} ---");
            sb.AppendLine(note.Content);
            if (!string.IsNullOrEmpty(note.SourceUrl))
            {
                sb.AppendLine($"Source: {note.SourceUrl}");
            }
            sb.AppendLine($"Recorded: {note.Timestamp:u}");
            sb.AppendLine();
        }

        return sb.ToString();
    }

    [Description("Gets the total number of notes saved so far.")]
    public string GetNoteCount()
    {
        return $"Total notes saved: {_notes.Count}";
    }

    public IReadOnlyList<ResearchNote> Notes => _notes.AsReadOnly();
}

public sealed record ResearchNote(string Title, string Content, string? SourceUrl, DateTime Timestamp);

