using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;
using ResearchAgent.Tools;

var builder = Host.CreateApplicationBuilder(args);

// Configure logging
builder.Logging.SetMinimumLevel(LogLevel.Information);
builder.Logging.AddSimpleConsole(options =>
{
    options.SingleLine = true;
    options.TimestampFormat = "HH:mm:ss ";
});

// Register tools as singletons so the agent accumulates state across iterations
builder.Services.AddHttpClient<WebSearchTool>();
builder.Services.AddSingleton<NoteTakingTool>();

// Register the chat client via MEAI abstraction
var apiKey = builder.Configuration["AI:ApiKey"]
    ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the AI:ApiKey configuration value or OPENAI_API_KEY environment variable.");

var modelId = builder.Configuration["AI:ModelId"] ?? "gpt-4o-mini-2024-07-18";

builder.Services.AddChatClient(chatClientBuilder => chatClientBuilder
    .UseLogging()
    .Use(new OpenAI.OpenAIClient(apiKey).AsChatClient(modelId)));

var host = builder.Build();

// Resolve services
var chatClient = host.Services.GetRequiredService<IChatClient>();
var webSearchTool = host.Services.GetRequiredService<WebSearchTool>();
var noteTakingTool = host.Services.GetRequiredService<NoteTakingTool>();
var logger = host.Services.GetRequiredService<ILoggerFactory>().CreateLogger("ResearchAgent");

// Define tools available to the agent
var tools = new AITool[]
{
    AIFunctionFactory.Create(webSearchTool.SearchWebAsync),
    AIFunctionFactory.Create(noteTakingTool.SaveNote),
    AIFunctionFactory.Create(noteTakingTool.GetAllNotes),
    AIFunctionFactory.Create(noteTakingTool.GetNoteCount),
};

// Get the research topic
Console.Write("Enter a topic to research: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");

// Set up the agent conversation with a system prompt
var messages = new List<ChatMessage>
{
    new(ChatRole.System, """
        You are a research agent. Your job is to thoroughly research a given topic using the available tools.

        Follow this process:
        1. Search the web for information on the topic using multiple relevant queries.
        2. For each useful finding, save a note capturing the key insight with its source.
        3. After gathering sufficient information (at least 3-5 notes), retrieve all your notes.
        4. Provide a final comprehensive summary of your research findings, citing sources.

        Be thorough but focused. Use different search queries to explore various angles of the topic.
        """),
    new(ChatRole.User, $"Please research the following topic and provide a comprehensive summary: {topic}"),
};

// Configure agent options with guardrails
var chatOptions = new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 2048,
    Tools = [.. tools],
    ToolMode = ChatToolMode.Auto,
};

// Run the agent loop with iteration limits
const int maxIterations = 15;
var iteration = 0;

while (iteration < maxIterations)
{
    iteration++;
    logger.LogInformation("Agent iteration {Iteration}/{Max}", iteration, maxIterations);

    var response = await chatClient.GetResponseAsync(messages, chatOptions);

    // Add the response to conversation history
    messages.AddMessages(response);

    // Check if the model wants to call tools
    var hasToolCalls = response.Messages
        .Any(m => m.Contents.OfType<FunctionCallContent>().Any());

    if (!hasToolCalls)
    {
        // Agent has finished — print the final response
        Console.WriteLine("\n📋 Research Summary:");
        Console.WriteLine(new string('─', 60));
        var finalText = string.Join("", response.Messages
            .SelectMany(m => m.Contents.OfType<TextContent>())
            .Select(t => t.Text));
        Console.WriteLine(finalText);
        Console.WriteLine(new string('─', 60));
        break;
    }
}

if (iteration >= maxIterations)
{
    logger.LogWarning("Agent reached maximum iterations ({Max}). Stopping.", maxIterations);
    Console.WriteLine("\n⚠️  Agent reached the iteration limit. Partial results:");
    foreach (var note in noteTakingTool.Notes)
    {
        Console.WriteLine($"  • {note.Title}: {note.Content}");
    }
}

Console.WriteLine($"\n✅ Research complete. {noteTakingTool.Notes.Count} notes collected in {iteration} iterations.");

