using Microsoft.Extensions.AI;
using Microsoft.Extensions.DependencyInjection;
using Microsoft.Extensions.Hosting;
using Microsoft.Extensions.Logging;
using ResearchAgent.Tools;

var builder = Host.CreateApplicationBuilder(args);

builder.Logging.SetMinimumLevel(LogLevel.Information);
builder.Logging.AddSimpleConsole(options =>
{
    options.SingleLine = true;
    options.TimestampFormat = "HH:mm:ss ";
});

builder.Services.AddSingleton<WebSearchTool>();
builder.Services.AddSingleton<NoteTakingTool>();
builder.Services.AddSingleton<HttpClient>();

// Register the chat client via MEAI abstraction
var apiKey = builder.Configuration["AI:ApiKey"]
    ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the AI:ApiKey configuration value or OPENAI_API_KEY environment variable.");

var modelId = builder.Configuration["AI:ModelId"] ?? "gpt-4o-mini-2024-07-18";

builder.Services.AddChatClient(
    sp => new OpenAIChatClient(
        new OpenAI.OpenAIClient(apiKey).GetChatClient(modelId)));

var host = builder.Build();

// Resolve services
var chatClient = host.Services.GetRequiredService<IChatClient>();
var webSearchTool = host.Services.GetRequiredService<WebSearchTool>();
var noteTakingTool = host.Services.GetRequiredService<NoteTakingTool>();
var loggerFactory = host.Services.GetRequiredService<ILoggerFactory>();
var logger = loggerFactory.CreateLogger("ResearchAgent");

// Define tools available to the agent
var tools = new List<AITool>
{
    AIFunctionFactory.Create(webSearchTool.SearchWebAsync),
    AIFunctionFactory.Create(noteTakingTool.SaveNote),
    AIFunctionFactory.Create(noteTakingTool.GetAllNotes),
    AIFunctionFactory.Create(noteTakingTool.GetNoteCount),
};

// Get the research topic
Console.Write("Enter a topic to research: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");

// Create the agent with ChatClientAgent from Microsoft.Agents.AI
var agent = new ChatClientAgent(
    chatClient,
    new ChatClientAgentOptions
    {
        Name = "ResearchAgent",
        Description = "An AI agent that researches topics by searching the web and taking notes.",
        ChatOptions = new ChatOptions
        {
            Temperature = 0f,
            MaxOutputTokens = 2048,
            Tools = [.. tools],
            ToolMode = ChatToolMode.Auto,
        },
    },
    loggerFactory);

// Prepare the conversation
var messages = new List<ChatMessage>
{
    new(ChatRole.System, """
        You are a research agent. Your job is to thoroughly research a given topic using the available tools.

        Follow this process:
        1. Search the web for information on the topic using multiple relevant queries.
        2. For each useful finding, save a note capturing the key insight with its source.
        3. After gathering sufficient information (at least 3-5 notes), retrieve all your notes.
        4. Provide a final comprehensive summary of your research findings, citing sources.

        Be thorough but focused. Use different search queries to explore various angles of the topic.
        """),
    new(ChatRole.User, $"Please research the following topic and provide a comprehensive summary: {topic}"),
};

// Run the agent with iteration guardrails
var runOptions = new ChatClientAgentRunOptions
{
    ChatOptions = new ChatOptions
    {
        MaxOutputTokens = 2048,
    },
};

Console.WriteLine("Agent is working...\n");

await foreach (var update in agent.RunStreamingAsync(messages, options: runOptions))
{
    if (update.Text is { Length: > 0 } text)
    {
        Console.Write(text);
    }
}

Console.WriteLine($"\n\n{'─', 0}");
Console.WriteLine($"✅ Research complete. {noteTakingTool.Notes.Count} notes collected.");

