1. using Microsoft.Agents.AI;
2. using Microsoft.Extensions.AI;
3. using Microsoft.Extensions.DependencyInjection;
4. using Microsoft.Extensions.Hosting;
5. using Microsoft.Extensions.Logging;
6. using ResearchAgent.Tools;
7. 
8. var builder = Host.CreateApplicationBuilder(args);
9. 
10. builder.Logging.SetMinimumLevel(LogLevel.Information);
11. builder.Logging.AddSimpleConsole(options =>
12. {
13.     options.SingleLine = true;
14.     options.TimestampFormat = "HH:mm:ss ";
15. });
16. 
17. builder.Services.AddSingleton<WebSearchTool>();
18. builder.Services.AddSingleton<NoteTakingTool>();
19. builder.Services.AddSingleton<HttpClient>();
20. 
21. // Register the chat client via MEAI abstraction
22. var apiKey = builder.Configuration["AI:ApiKey"]
23.     ?? Environment.GetEnvironmentVariable("OPENAI_API_KEY")
24.     ?? throw new InvalidOperationException(
25.         "Set the AI:ApiKey configuration value or OPENAI_API_KEY environment variable.");
26. 
27. var modelId = builder.Configuration["AI:ModelId"] ?? "gpt-4o-mini-2024-07-18";
28. 
29. builder.Services.AddChatClient(
30.     sp => new OpenAI.OpenAIClient(apiKey)
31.         .GetChatClient(modelId)
32.         .AsIChatClient());
33. 
34. var host = builder.Build();
35. 
36. // Resolve services
37. var chatClient = host.Services.GetRequiredService<IChatClient>();
38. var webSearchTool = host.Services.GetRequiredService<WebSearchTool>();
39. var noteTakingTool = host.Services.GetRequiredService<NoteTakingTool>();
40. var loggerFactory = host.Services.GetRequiredService<ILoggerFactory>();
41. var logger = loggerFactory.CreateLogger("ResearchAgent");
42. 
43. // Define tools available to the agent
44. var tools = new List<AITool>
45. {
46.     AIFunctionFactory.Create(webSearchTool.SearchWebAsync),
47.     AIFunctionFactory.Create(noteTakingTool.SaveNote),
48.     AIFunctionFactory.Create(noteTakingTool.GetAllNotes),
49.     AIFunctionFactory.Create(noteTakingTool.GetNoteCount),
50. };
51. 
52. // Get the research topic
53. Console.Write("Enter a topic to research: ");
54. var topic = Console.ReadLine()?.Trim();
55. if (string.IsNullOrEmpty(topic))
56. {
57.     Console.WriteLine("No topic provided. Exiting.");
58.     return;
59. }
60. 
61. Console.WriteLine($"\n🔍 Researching: {topic}\n");
62. 
63. // Create the agent with ChatClientAgent from Microsoft.Agents.AI
64. var agent = new ChatClientAgent(
65.     chatClient,
66.     new ChatClientAgentOptions
67.     {
68.         Name = "ResearchAgent",
69.         Description = "An AI agent that researches topics by searching the web and taking notes.",
70.         ChatOptions = new ChatOptions
71.         {
72.             Temperature = 0f,
73.             MaxOutputTokens = 2048,
74.             Tools = [.. tools],
75.             ToolMode = ChatToolMode.Auto,
76.         },
77.     },
78.     loggerFactory);
79. 
80. // Prepare the conversation
81. var messages = new List<ChatMessage>
82. {
83.     new(ChatRole.System, """
84.         You are a research agent. Your job is to thoroughly research a given topic using the available tools.
85. 
86.         Follow this process:
87.         1. Search the web for information on the topic using multiple relevant queries.
88.         2. For each useful finding, save a note capturing the key insight with its source.
89.         3. After gathering sufficient information (at least 3-5 notes), retrieve all your notes.
90.         4. Provide a final comprehensive summary of your research findings, citing sources.
91. 
92.         Be thorough but focused. Use different search queries to explore various angles of the topic.
93.         """),
94.     new(ChatRole.User, $"Please research the following topic and provide a comprehensive summary: {topic}"),
95. };
96. 
97. // Run the agent with iteration guardrails
98. var runOptions = new ChatClientAgentRunOptions
99. {
100.     ChatOptions = new ChatOptions
101.     {
102.         MaxOutputTokens = 2048,
103.     },
104. };
105. 
